var b="url",c="对账结算详情_dzjs_-发起_未记账.html",d="generationDate",e=new Date(1781588668176.73),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="eda7f3aadf5f4e9693560ea0dce8cf7b",v="type",w="Axure:Page",x="对账结算详情(DZJS)-发起/未记账",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="651f8c3105544a5bb9c1b35f10a9d9a2",E="label",F="结算时间：",G="说明",H="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">发起/未记账</span></p><p><span>1.下拉域启用</span></p><p><span>2.默认</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">当日当前时分</span></p><p><span>3.格式：yyyy-MM-dd HH:mm</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">已记账</span></p><p><span>1.文本</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#333333;\">展示本单据【记账】时记录的数据</span></p>",I="2",J="f8b66cc4f12b4110b6e7f11f4c8c0189",K="结算总额：500.00",L="<p><span>1.跟随[对账明细]和[附加款项]进行自动计算</span></p><p><span>2.结算总额 = [对账明细]的Σ“对账金额”+[附加款项]的Σ“追加金额”-[附加款项]的Σ“扣除金额”</span></p>",M="3",N="bf534b39346a4b4d9f665d6e6a4c4c3c",O="对账明细",P="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">清单描述</span></p><p><span>1.数据行来源：上游[出入库明细]勾选对应行</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">出入库数量</span></p><p><span>[出入库明细]对应行的'数量'</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">出入库单价</span></p><p><span>[出入库明细]对应行的'含税单价'</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">采购单价</span></p><p><span>1.仅类型为'采购入库'、'采购入库(扣除)'、'红冲入库'、'采购退货出库'、'采购退货出库(补入)'的行查询该字段值 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">(不用存，实时查最新的)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.'采购入库'、'采购入库(扣除)'：当前行于[出入库明细]内所属</span><span style=\"text-decoration:underline ;\">入库任务(RKRW)</span><span>入库清单中关联生成至[采购物料清单]数据行的'含税单价'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.'红冲入库'、'采购退货出库'、'采购退货出库(补入)'：当前行于[出入库明细]内所属</span><span style=\"text-decoration:underline ;\">采购退货单(CGTH)</span><span>对应的</span><span style=\"text-decoration:underline ;\">采购订单(CGDD)</span><span>对应的[采购物料清单]数据行的'含税单价'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.其它类型：展示为空，而不是0</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">加工单价</span></p><p><span>[出入库明细]对应行的'加工单价'</span></p>",Q="4",R="58b7d212d3324ff6910be291fb288898",S="对账数量",T="<p><span>1.默认值：取'出入库数量'</span></p><p><span>2.格式：保留4位小数</span></p>",U="5",V="724d4dafdde74481b67384fe1fb5c188",W="确认",X="<p><span>1.</span><span style=\"text-decoration:underline ;\">对账明细</span><span>中对应[物料仓库系统&gt;&gt;库存分析：出入库明细]的上游行的“结算状态”变更为</span><span style=\"color:#0CB732;\">已结算</span></p><p><span>2.在[财务管理系统-应付管理-</span><span style=\"color:#333333;\">采购结算单</span><span>]中生成一条记录：</span><span style=\"color:#0083FC;\">DZJS+2位年份+2位月份+4位流水</span></p><p><span>3.首次创建，结算单的“未付金额”初始化为'0.00'</span></p>",Y="6",Z="fcfa43f7d6034999b870804ca329a6af",ba="结算单价",bb="<p><span>1.默认值：取'出入库单价'</span></p><p><span>2.格式：保留4位小数</span></p>",bc="7",bd="9a64bb24d5ab4beebbdd67d1d534b893",be="对账金额",bf="<p><span>1.对账金额 = 对账数量 * 结算单价</span></p>",bg="8",bh="9a7dbb2b6eba4df488334e043d27e4ef",bi=" 同步单价",bj="<p><span>1.【物料单价】：将'出入库单价'列的数值覆盖至'结算单价'</span></p><p><span>2.【采购单价】：将'采购单价'列</span><span style=\"color:#D9001B;\">非空</span><span>的数值覆盖至'结算单价'</span></p><p><span>3.【加工单价】：将'加工单价'列的数值覆盖至'结算单价'</span></p>",bk="9",bl="9f9842f50a6b483a9131c9e222b37641",bm="* 金额",bn="<p><span>正数，保留两位小数</span></p>",bo="10",bp="4697ac65ffb748ada763b609966c0fd8",bq="保存",br="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新增发起</span></p><p><span>1.弹窗进行二次确认</span></p><p><span>2.二次确认逻辑见弹窗内批注</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">未记账</span></p><p><span>1.无须二次确认，直接返回列表页</span></p><p><span>2.更新单据信息</span></p><p><span>3.更新该结算单的“修改人”及“修改时间”</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">已记账</span></p><p><span>1.不展示该按钮</span></p>",bs="style",bt="baseStyle",bu="627587b6038d43cca051c114ac41ad32",bv="pageAlignment",bw="center",bx="fill",by="fillType",bz="solid",bA="color",bB=0xFFFFFFFF,bC="image",bD="imageAlignment",bE="near",bF="imageRepeat",bG="auto",bH="favicon",bI="sketchFactor",bJ="0",bK="colorStyle",bL="appliedColor",bM="fontName",bN="Applied Font",bO="borderWidth",bP="borderVisibility",bQ="borderFill",bR=0xFF797979,bS="cornerRadius",bT="cornerVisibility",bU="outerShadow",bV="on",bW=false,bX="offsetX",bY=5,bZ="offsetY",ca="blurRadius",cb="spread",cc="r",cd=0,ce="g",cf="b",cg="a",ch=0.349019607843137,ci="adaptiveStyles",cj="interactionMap",ck="diagram",cl="objects",cm="id",cn="f0e3bf38540b464ea3f60112e8024363",co="friendlyType",cp="标题-1340",cq="referenceDiagramObject",cr="styleType",cs="visible",ct=true,cu=1340,cv=110,cw="imageOverrides",cx="masterId",cy="bdaeed3774644546913b266f76aa115f",cz="45d7d5de4d5945abbc8316427db88c2a",cA="矩形",cB="vectorShape",cC=196,cD=16,cE="e1688a153f8846659e664df5cd9ec7b7",cF="location",cG="x",cH=20,cI="y",cJ=138,cK="generateCompound",cL="4697ac65ffb748ada763b609966c0fd8",cM="'微软雅黑', sans-serif",cN="foreGroundFill",cO=0xFF000000,cP="opacity",cQ=1,cR=60,cS=32,cT="5f44b79bbafd43f5b58194dfb3f6f145",cU=0xFF339